// ╔══════════════════════════════════════════════════════════╗
// ║   TaskBarHero — Frida Hile Ayarları ve Kodları           ║
// ║   Yazar: Pantheon                                        ║
// ╚══════════════════════════════════════════════════════════╝

// ==============================================================================
// ⚙️ HİLE AYARLARI (İstediğiniz değerleri buradan değiştirebilirsiniz)
// ==============================================================================
const GODMODE      = true;      // true: Ölümsüzlük Açık  | false: Kapalı
const ONE_HIT_KILL = true;      // true: Tek Atma Açık   | false: Kapalı
const OHK_HASAR    = 9000.0;  // Düşmana verilecek hasar miktarı (Arttırabilirsiniz)

// ==============================================================================
// 🛠️ OYUN OFSETLERİ VE KODLARI (v2.5 yaması için güncel hasar alma fonksiyonları)
// ==============================================================================
const RVA_HERO_GQM    = 0xC00CE0; // Hero.gqm metot adresi (Kahramanın hasar aldığı yer)
const RVA_MONSTER_GQM = 0xC05780; // Monster.gqm metot adresi (Canavarların hasar aldığı yer)
const OFF_DAMAGE      = 0x08;     // DamageInfo->OriginDamage ofseti (float)

function banner() {
    console.log('\n\x1b[36m╔══════════════════════════════════════════════════╗\x1b[0m');
    console.log('\x1b[36m║   TaskBarHero Hook Script v2.5 • Pantheon        ║\x1b[0m');
    console.log('\x1b[36m║   Frida Sürümü: ' + Frida.version.padEnd(32) + ' ║\x1b[0m');
    console.log('\x1b[36m╠══════════════════════════════════════════════════╣\x1b[0m');
    console.log('║  Godmode      : ' + (GODMODE      ? '\x1b[32m✔ AÇIK \x1b[0m' : '\x1b[31m✘ KAPALI\x1b[0m') + '                        ║');
    console.log('║  One Hit Kill : ' + (ONE_HIT_KILL ? '\x1b[32m✔ AÇIK \x1b[0m' : '\x1b[31m✘ KAPALI\x1b[0m') + '  (' + String(OHK_HASAR).padEnd(10) + ' hasar)  ║');
    console.log('\x1b[36m╚══════════════════════════════════════════════════╝\x1b[0m\n');
}

banner();

const mod = Process.findModuleByName('GameAssembly.dll');
if (!mod) {
    console.log('[-] GameAssembly.dll bulunamadı — oyun açık mı?');
} else {
    console.log('[+] GameAssembly.dll @ ' + mod.base);

    // 1. Kahraman Hasar Kontrolü (Godmode)
    try {
        Interceptor.attach(mod.base.add(RVA_HERO_GQM), {
            onEnter(args) {
                if (GODMODE) {
                    const dmgInf = args[1];
                    if (!dmgInf.isNull()) {
                        dmgInf.add(OFF_DAMAGE).writeFloat(0.0); // Kahramana gelen hasarı 0 yap
                        console.log('[✔] Godmode — Kahramana gelen hasar engellendi.');
                    }
                }
            }
        });
        console.log('[+] Hook Aktif: Hero.gqm (Godmode)');
    } catch (err) {
        console.log('[-] Hero.gqm kancalanamadı: ' + err.message);
    }

    // 2. Canavar Hasar Kontrolü (One-Hit Kill)
    try {
        Interceptor.attach(mod.base.add(RVA_MONSTER_GQM), {
            onEnter(args) {
                if (ONE_HIT_KILL) {
                    const dmgInf = args[1];
                    if (!dmgInf.isNull()) {
                        dmgInf.add(OFF_DAMAGE).writeFloat(OHK_HASAR); // Canavara giden hasarı OHK yap
                        console.log('[✔] One Hit Kill — Düşmana yüksek hasar verildi.');
                    }
                }
            }
        });
        console.log('[+] Hook Aktif: Monster.gqm (One-Hit Kill)');
    } catch (err) {
        console.log('[-] Monster.gqm kancalanamadı: ' + err.message);
    }
}
